#[napi(string_enum, js_name = "SymbolKind")]
#[derive(Clone)]
pub enum JsSymbolKind {
    Variable,
    Constant,
    Function,
    Class,
    Type,
    Interface,
    Enum,
    Module,
    Other,
}

#[allow(clippy::derivable_impls)]
impl Default for JsSymbolKind {
    fn default() -> Self {
        Self::Variable
    }
}

