#[napi(js_name = "getLanguage")]
pub fn get_language(env: &napi::Env, name: String) -> napi::Result<napi::bindgen_prelude::Object<'_>> {
    let value = tree_sitter_language_pack::get_language(&name)
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    // SAFETY: `into_raw()` transfers ownership of the raw pointer. The downstream JS
    // runtime keeps the External alive as long as the returned object is reachable;
    // dropping the pointer prematurely would be a use-after-free.
    let ptr = value.into_raw() as *mut std::ffi::c_void;
    let mut obj = napi::bindgen_prelude::Object::new(env)?;
    let env_raw = env.raw();
    let mut external_value: napi::sys::napi_value = std::ptr::null_mut();
    let create_status = unsafe { napi_create_external(env_raw, ptr, None, std::ptr::null_mut(), &mut external_value) };
    if create_status != napi::sys::Status::napi_ok {
        return Err(napi::Error::new(
            napi::Status::GenericFailure,
            format!("napi_create_external failed: status={create_status}"),
        ));
    }
    let status = unsafe { napi_type_tag_object(env_raw, external_value, &__ALEF_CAPSULE_TAG_LANGUAGE) };
    if status != napi::sys::Status::napi_ok {
        return Err(napi::Error::new(
            napi::Status::GenericFailure,
            format!("napi_type_tag_object failed: status={status}"),
        ));
    }
    // SAFETY: external_value was just created by napi_create_external on env_raw.
    let unknown = unsafe { napi::bindgen_prelude::Unknown::from_raw_unchecked(env_raw, external_value) };
    obj.set_named_property("language", unknown)?;
    Ok(obj)
}

/// Get a [`Parser`] pre-configured for the given language.
///
/// This is a convenience function that calls [`get_language`] and configures
/// a new parser in one step.
///
/// # Errors
///
/// Returns [`Error::LanguageNotFound`] if the language is not recognized, or
/// [`Error::ParserSetup`] if the language cannot be applied to the parser.
///
/// # Example
///
/// ```no_run
/// use tree_sitter_language_pack::get_parser;
///
/// let mut parser = get_parser("rust")?;
/// let tree = parser.parse("fn main() {}").expect("parse failed");
/// assert!(!tree.root_node().has_error());
/// # Ok::<(), tree_sitter_language_pack::Error>(())
/// ```
#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "getParser")]
pub fn get_parser(name: String) -> Result<JsParser> {
    tree_sitter_language_pack::get_parser(&name)
        .map(|val| JsParser {
            inner: Arc::new(std::sync::Mutex::new(val)),
        })
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

/// Detect language name from a file path or extension.
///
/// This compatibility alias matches the pre-Alef Python binding API.
#[napi(js_name = "detectLanguage")]
pub fn detect_language(path: String) -> Option<String> {
    tree_sitter_language_pack::detect_language(&path).map(Into::into)
}

