// Error variant name constants
pub const ERROR_ERROR_LANGUAGE_NOT_FOUND: &str = "LanguageNotFound";
pub const ERROR_ERROR_DYNAMIC_LOAD: &str = "DynamicLoad";
pub const ERROR_ERROR_NULL_LANGUAGE_POINTER: &str = "NullLanguagePointer";
pub const ERROR_ERROR_PARSER_SETUP: &str = "ParserSetup";
pub const ERROR_ERROR_LOCK_POISONED: &str = "LockPoisoned";
pub const ERROR_ERROR_CONFIG: &str = "Config";
pub const ERROR_ERROR_PARSE_FAILED: &str = "ParseFailed";
pub const ERROR_ERROR_QUERY_ERROR: &str = "QueryError";
pub const ERROR_ERROR_INVALID_RANGE: &str = "InvalidRange";
pub const ERROR_ERROR_IO: &str = "Io";

/// Convert a `tree_sitter_language_pack::error::Error` error to a NAPI error.
#[allow(dead_code)]
fn error_to_napi_err(e: tree_sitter_language_pack::error::Error) -> napi::Error {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        tree_sitter_language_pack::error::Error::LanguageNotFound(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[LanguageNotFound] {}", msg))
        }
        tree_sitter_language_pack::error::Error::DynamicLoad(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[DynamicLoad] {}", msg))
        }
        tree_sitter_language_pack::error::Error::NullLanguagePointer(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[NullLanguagePointer] {}", msg))
        }
        tree_sitter_language_pack::error::Error::ParserSetup(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ParserSetup] {}", msg))
        }
        tree_sitter_language_pack::error::Error::LockPoisoned(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[LockPoisoned] {}", msg))
        }
        tree_sitter_language_pack::error::Error::Config(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Config] {}", msg))
        }
        tree_sitter_language_pack::error::Error::ParseFailed => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ParseFailed] {}", msg))
        }
        tree_sitter_language_pack::error::Error::QueryError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[QueryError] {}", msg))
        }
        tree_sitter_language_pack::error::Error::InvalidRange(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[InvalidRange] {}", msg))
        }
        tree_sitter_language_pack::error::Error::Io(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Io] {}", msg))
        }
        _ => napi::Error::new(napi::Status::GenericFailure, msg),
    }
}
